import{_ as a,c as s,o as t,ae as n}from"./chunks/framework.Cd-3tpCq.js";const m=JSON.parse('{"title":"Étape 7.1 — Content Templates dans Canvas","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-canvas/content-templates.md","filePath":"drupal-canvas/content-templates.md"}'),l={name:"drupal-canvas/content-templates.md"};function i(p,e,o,r,d,c){return t(),s("div",null,e[0]||(e[0]=[n(`<h1 id="etape-7-1-—-content-templates-dans-canvas" tabindex="-1">Étape 7.1 — Content Templates dans Canvas <a class="header-anchor" href="#etape-7-1-—-content-templates-dans-canvas" aria-label="Permalink to &quot;Étape 7.1 — Content Templates dans Canvas&quot;">​</a></h1><h2 id="objectif" tabindex="-1">Objectif <a class="header-anchor" href="#objectif" aria-label="Permalink to &quot;Objectif&quot;">​</a></h2><p>Apprendre à utiliser Canvas pour <strong>afficher des contenus Drupal structurés</strong> (nœuds, comme des articles de blog) avec une mise en page Canvas. Les <strong>Content Templates</strong> permettent de définir l&#39;affichage d&#39;un type de contenu via Canvas au lieu des templates Twig classiques.</p><h2 id="le-probleme-que-ca-resout" tabindex="-1">Le problème que ça résout <a class="header-anchor" href="#le-probleme-que-ca-resout" aria-label="Permalink to &quot;Le problème que ça résout&quot;">​</a></h2><p>Sans Canvas, pour personnaliser l&#39;affichage d&#39;un type de contenu (ex: Article), vous devez :</p><ul><li>Créer un template Twig <code>node--article--full.html.twig</code></li><li>Écrire du HTML/Twig à la main</li><li>Vider le cache à chaque modification</li></ul><p>Avec les <strong>Content Templates</strong> de Canvas, vous pouvez définir cette mise en page <strong>visuellement dans l&#39;éditeur Canvas</strong>, en utilisant les champs du nœud comme props dans vos composants.</p><h2 id="creer-un-content-template-pour-les-articles" tabindex="-1">Créer un Content Template pour les Articles <a class="header-anchor" href="#creer-un-content-template-pour-les-articles" aria-label="Permalink to &quot;Créer un Content Template pour les Articles&quot;">​</a></h2><h3 id="etape-1-—-acceder-aux-content-templates" tabindex="-1">Étape 1 — Accéder aux Content Templates <a class="header-anchor" href="#etape-1-—-acceder-aux-content-templates" aria-label="Permalink to &quot;Étape 1 — Accéder aux Content Templates&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Canvas → Content Templates → Ajouter un template</span></span></code></pre></div><p>Ou depuis :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Administration → Structure → Types de contenu → Article → Canvas Templates</span></span></code></pre></div><h3 id="etape-2-—-choisir-le-type-de-contenu-et-le-mode-d-affichage" tabindex="-1">Étape 2 — Choisir le type de contenu et le mode d&#39;affichage <a class="header-anchor" href="#etape-2-—-choisir-le-type-de-contenu-et-le-mode-d-affichage" aria-label="Permalink to &quot;Étape 2 — Choisir le type de contenu et le mode d&#39;affichage&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Paramètre</th><th>Valeur</th></tr></thead><tbody><tr><td>Type de contenu</td><td>Article</td></tr><tr><td>Mode d&#39;affichage</td><td>Complet (Full)</td></tr></tbody></table><h3 id="etape-3-—-construire-la-mise-en-page-dans-l-editeur-canvas" tabindex="-1">Étape 3 — Construire la mise en page dans l&#39;éditeur Canvas <a class="header-anchor" href="#etape-3-—-construire-la-mise-en-page-dans-l-editeur-canvas" aria-label="Permalink to &quot;Étape 3 — Construire la mise en page dans l&#39;éditeur Canvas&quot;">​</a></h3><p>L&#39;éditeur s&#39;ouvre avec des <strong>jetons de champs</strong> disponibles dans le panneau gauche. Ce sont les champs réels du type de contenu que vous pouvez injecter dans vos composants.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Panneau gauche — Champs disponibles :</span></span>
<span class="line"><span>├── Titre (field:title)</span></span>
<span class="line"><span>├── Corps (field:body)</span></span>
<span class="line"><span>├── Image (field:field_image)</span></span>
<span class="line"><span>├── Date de publication (field:created)</span></span>
<span class="line"><span>├── Auteur (field:uid)</span></span>
<span class="line"><span>└── Tags (field:field_tags)</span></span></code></pre></div><h3 id="etape-4-—-exemple-de-mise-en-page-pour-un-article" tabindex="-1">Étape 4 — Exemple de mise en page pour un Article <a class="header-anchor" href="#etape-4-—-exemple-de-mise-en-page-pour-un-article" aria-label="Permalink to &quot;Étape 4 — Exemple de mise en page pour un Article&quot;">​</a></h3><p><strong>Section 1 — En-tête de l&#39;article</strong></p><p>Composant <strong>Page Header</strong> :</p><ul><li>Titre → glissez le jeton <code>Titre (field:title)</code> dans la prop Titre</li><li>Le titre s&#39;affichera dynamiquement depuis le nœud Drupal</li></ul><p><strong>Section 2 — Contenu</strong></p><p>Grid 2 colonnes (2/3 + 1/3) :</p><p><em>Colonne principale :</em></p><ul><li>Image → jeton <code>Image (field:field_image)</code></li><li>Corps → jeton <code>Corps (field:body)</code></li></ul><p><em>Sidebar :</em></p><ul><li>Date : <code>Publié le {field:created}</code></li><li>Auteur : <code>Par {field:uid}</code></li><li>Tags : jeton <code>Tags (field:field_tags)</code></li></ul><h3 id="etape-5-—-previsualiser-avec-un-vrai-nœud" tabindex="-1">Étape 5 — Prévisualiser avec un vrai nœud <a class="header-anchor" href="#etape-5-—-previsualiser-avec-un-vrai-nœud" aria-label="Permalink to &quot;Étape 5 — Prévisualiser avec un vrai nœud&quot;">​</a></h3><p>Canvas vous permet de prévisualiser le template avec un <strong>nœud existant</strong> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Barre d&#39;outils → Prévisualiser → Sélectionner un nœud Article</span></span></code></pre></div><p>Vous voyez immédiatement le rendu avec de vraies données.</p><h2 id="utiliser-les-jetons-dans-les-composants" tabindex="-1">Utiliser les jetons dans les composants <a class="header-anchor" href="#utiliser-les-jetons-dans-les-composants" aria-label="Permalink to &quot;Utiliser les jetons dans les composants&quot;">​</a></h2><p>Dans vos composants SDC, les props peuvent recevoir des jetons Canvas :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Composant Card :</span></span>
<span class="line"><span>  Titre → [field:title]</span></span>
<span class="line"><span>  Texte → [field:body:summary]</span></span>
<span class="line"><span>  Image → [field:field_image:url]</span></span>
<span class="line"><span>  URL   → [node:url]</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Mode de rendu des champs</p><p>Chaque champ Drupal peut être affiché dans différents <strong>modes</strong> (formatters) :</p><ul><li><code>body</code> → HTML complet</li><li><code>body:summary</code> → Résumé</li><li><code>field_image:url</code> → URL de l&#39;image</li><li><code>field_image:alt</code> → Texte alt de l&#39;image</li></ul><p>Ces modes sont accessibles depuis le sélecteur de jetons dans l&#39;éditeur Canvas.</p></div><h2 id="exemple-complet-template-article" tabindex="-1">Exemple complet : template Article <a class="header-anchor" href="#exemple-complet-template-article" aria-label="Permalink to &quot;Exemple complet : template Article&quot;">​</a></h2><p>Voici la structure cible pour un article de blog :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Blog &gt; [Titre de l&#39;article]                        │</span></span>
<span class="line"><span>│  [TITRE DE L&#39;ARTICLE]                               │</span></span>
<span class="line"><span>│  Publié le 15 janvier 2025 par Jean Dupont          │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│  [IMAGE PRINCIPALE]                                 │</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│  [CONTENU DE L&#39;ARTICLE]                             │</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│  Lorem ipsum dolor sit amet, consectetur            │</span></span>
<span class="line"><span>│  adipiscing elit. Sed do eiusmod tempor…            │</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│  Tags : [Drupal] [Canvas] [Tutoriel]                │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="avantages-par-rapport-aux-templates-twig-classiques" tabindex="-1">Avantages par rapport aux templates Twig classiques <a class="header-anchor" href="#avantages-par-rapport-aux-templates-twig-classiques" aria-label="Permalink to &quot;Avantages par rapport aux templates Twig classiques&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Template Twig classique</th><th>Content Template Canvas</th></tr></thead><tbody><tr><td>Modification</td><td>Fichier + cache à vider</td><td>Interface visuelle, instantané</td></tr><tr><td>Compétences requises</td><td>Twig + HTML</td><td>Aucune compétence technique</td></tr><tr><td>Réutilisation</td><td>Copier-coller du code</td><td>Bibliothèque de Patterns</td></tr><tr><td>Prévisualisation</td><td>Après sauvegarde + cache</td><td>Temps réel dans l&#39;éditeur</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Limitations</p><p>Les Content Templates Canvas ne remplacent pas totalement les templates Twig pour les cas complexes (logique conditionnelle avancée, preprocessing de données). Pour des cas simples à moyennement complexes, ils sont largement suffisants.</p></div>`,41)]))}const h=a(l,[["render",i]]);export{m as __pageData,h as default};
